// Helper: get day index from Date object
PD.di=function(dt){
  var s=new Date(PD.start+'T00:00:00Z');
  return Math.round((Date.UTC(dt.getFullYear(),dt.getMonth(),dt.getDate())-s.getTime())/(86400000));
};

// Helper: get planet sidereal longitudes for a date
// Returns {sun,moon,mars,jup,sat,ven,mer,rahu,ketu} in degrees
PD.geo=function(dt){
  var i=PD.di(dt);
  if(i<0||i>=PD.p.length)return null;
  var row=PD.p[i];
  return{sun:row[0],moon:row[1],mars:row[2],jup:row[3],sat:row[4],ven:row[5],mer:row[6],rahu:row[7],ketu:(row[7]+180)%360};
};

// Helper: get Moon at specific hour (0-23 IST)
// Uses 6h interpolation for transitions
PD.moonAt=function(dt,hIST){
  var i=PD.di(dt);
  var hUT=hIST-5.5;
  if(hUT<0){i--;hUT+=24;}
  var idx6=i*4+hUT/6;
  var i6=Math.floor(idx6),f=idx6-i6;
  if(i6<0)return PD.m6[0];
  if(i6>=PD.m6.length-1)return PD.m6[PD.m6.length-1];
  var l0=PD.m6[i6],l1=PD.m6[i6+1];
  var d=l1-l0;if(d>180)d-=360;if(d<-180)d+=360;
  return(l0+f*d+360)%360;
};

// Lahiri Ayanamsa
PD.ay=function(jd){var T=(jd-2451545)/36525;return 23.819167+1.548210*T;};

// Sunrise/Sunset for date
PD.sun=function(dt){var i=PD.di(dt);if(i<0||i>=PD.r.length)return{rise:6,set:18};return{rise:PD.r[i],set:PD.s[i]};};
